def seed():
    conn = get_db()
    ph = PH
    inserted = skipped = 0
    for row in GOV_MCQS:
        folder, topic, q_text, opt_a, opt_b, opt_c, opt_d, ans, diff, exp = row
        existing = db_exec(conn,
            f"SELECT id FROM questions WHERE folder={ph} AND topic={ph} AND question_text={ph}",
            (folder, topic, q_text)).fetchone()
        if existing:
            skipped += 1
            continue
        db_exec(conn,
            f"""INSERT INTO questions
                (folder, topic, source_file, question_text,
                 option_a, option_b, option_c, option_d,
                 correct_answer, difficulty, explanation)
                VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph})""",
            (folder, topic, "governance_500_seed", q_text,
             opt_a, opt_b, opt_c, opt_d, ans, diff, exp))
        inserted += 1
    conn.commit()
    conn.close()
    total = db_exec(get_db(),
        f"SELECT COUNT(*) FROM questions WHERE folder={ph} AND topic={ph}",
        ("AP_HC", "Governance")).fetchone()[0]
    print(f"✅ Inserted: {inserted}  |  Skipped (duplicates): {skipped}  |  Total Governance: {total}")

# Legacy alias for direct path usage
def seed_governance(db_path=None):
    seed()

if __name__ == "__main__":
    seed()